use std::io::{self, Read};
fn justify(words: Vec<String>, max_width: usize) -> Vec<String> { let mut res = Vec::new(); let mut i = 0usize; while i < words.len() { let mut j = i; let mut total = 0usize; while j < words.len() && total + words[j].len() + (j - i) <= max_width { total += words[j].len(); j += 1; } let gaps = j - i - 1; let line = if j == words.len() || gaps == 0 { let mut line = words[i..j].join(" "); line.push_str(&" ".repeat(max_width - line.len())); line } else { let spaces = max_width - total; let base = spaces / gaps; let extra = spaces % gaps; let mut line = String::new(); for k in i..j-1 { line.push_str(&words[k]); line.push_str(&" ".repeat(base + if k - i < extra { 1 } else { 0 })); } line.push_str(&words[j-1]); line }; res.push(line); i = j; } res }
fn main() { let mut input = String::new(); io::stdin().read_to_string(&mut input).unwrap(); let lines: Vec<String> = input.lines().map(|s| s.to_string()).collect(); if !lines.is_empty() { let mut idx = 0usize; let t: usize = lines[idx].parse().unwrap(); idx += 1; let mut out: Vec<String> = Vec::new(); for tc in 0..t { let n: usize = lines[idx].parse().unwrap(); idx += 1; let words = lines[idx..idx+n].to_vec(); idx += n; let width: usize = lines[idx].parse().unwrap(); idx += 1; let ans = justify(words, width); out.push(ans.len().to_string()); for s in ans { out.push(format!("|{}|", s)); } if tc + 1 < t { out.push("=".to_string()); } } print!("{}", out.join("\n")); } }
